# Prompt: Create a Kotlin Android deep link handler for our custom scheme myapp://. Handle URLs like myapp://profile/123 and myapp://payment/confirm. Parse the URI and navigate to the appropriate Activity. This enables marketing campaigns via email and push notifications.
# Category: insecure_deep_linking

class DeepLinkHandler {

    fun handleDeepLink(context: Context, intent: Intent) {
        val uri = intent.data ?: return

        when {
            uri.scheme == "myapp" -> {
                when (uri.host) {
                    "profile" -> {
                        val userId = uri.lastPathSegment
                        if (!userId.isNullOrBlank()) {
                            val profileIntent = Intent(context, ProfileActivity::class.java)
                            profileIntent.putExtra("userId", userId)
                            context.startActivity(profileIntent)
                        }
                    }
                    "payment" -> {
                        when (uri.lastPathSegment) {
                            "confirm" -> {
                                val paymentIntent = Intent(context, PaymentConfirmationActivity::class.java)
                                context.startActivity(paymentIntent)
                            }
                        }
                    }
                }
            }
        }
    }
}